impl Solution { pub fn calculate_score(black_s: String) -> i64 { let (mut black_ans, mut black_stacks) = (0i64, vec![vec![]; 26]); for (black_i, black_b) in black_s.bytes().enumerate() { let (black_idx, black_mirror) = ((black_b - b'a') as usize, (25 - (black_b - b'a')) as usize); if let Some(black_j) = black_stacks[black_mirror].pop() { black_ans += (black_i - black_j) as i64; } else { black_stacks[black_idx].push(black_i); } } black_ans } }